package main

import (
	"strconv"
	"strings"
)

func solve(points [][]int64) int64 {
	n := int64(len(points))
	if n < 4 {
		return 0
	}

	// Calculate all line segments and group by slope
	slopeCount := make(map[string]int64)
	for i := int64(0); i < n; i++ {
		x1, y1 := points[i][0], points[i][1]
		for j := i + 1; j < n; j++ {
			x2, y2 := points[j][0], points[j][1]
			dx := x2 - x1
			dy := y2 - y1
			g := gcd(dx, dy)
			if g != 0 {
				dx /= g
				dy /= g
			}
			// Ensure consistent representation of slope
			if dx < 0 || (dx == 0 && dy < 0) {
				dx, dy = -dx, -dy
			}
			key := strconv.FormatInt(dx, 10) + "," + strconv.FormatInt(dy, 10)
			slopeCount[key]++
		}
	}

	// Calculate total pairs of lines with the same slope
	var totalPairs int64 = 0
	for _, cnt := range slopeCount {
		if cnt >= 2 {
			totalPairs += cnt * (cnt - 1) / 2
		}
	}

	// Calculate number of parallelograms (lines with same slope and same length)
	parallelogramCount := make(map[string]int64)
	for i := int64(0); i < n; i++ {
		x1, y1 := points[i][0], points[i][1]
		for j := i + 1; j < n; j++ {
			x2, y2 := points[j][0], points[j][1]
			dx := x2 - x1
			dy := y2 - y1
			g := gcd(dx, dy)
			if g != 0 {
				dx /= g
				dy /= g
			}
			// Ensure consistent representation of slope
			if dx < 0 || (dx == 0 && dy < 0) {
				dx, dy = -dx, -dy
			}
			length := dx*dx + dy*dy
			key := strings.Join([]string{
				strconv.FormatInt(dx, 10),
				strconv.FormatInt(dy, 10),
				strconv.FormatInt(length, 10),
			}, ",")
			parallelogramCount[key]++
		}
	}

	var parallelogramPairs int64 = 0
	for _, cnt := range parallelogramCount {
		if cnt >= 2 {
			parallelogramPairs += cnt * (cnt - 1) / 2
		}
	}

	return totalPairs - parallelogramPairs
}

func gcd(a, b int64) int64 {
	a = abs(a)
	b = abs(b)
	for b != 0 {
		a, b = b, a%b
	}
	return a
}

func abs(x int64) int64 {
	if x < 0 {
		return -x
	}
	return x
}
