package main

import (
	"strconv"
	"strings"
)

func solve(points [][]int64) int64 {
	n := int64(len(points))
	if n < 4 {
		return 0
	}

	// Count all pairs of lines with the same slope
	allSlopes := make(map[string]int64)
	for i := int64(0); i < n; i++ {
		x1, y1 := points[i][0], points[i][1]
		for j := i + 1; j < n; j++ {
			x2, y2 := points[j][0], points[j][1]
			dx := x2 - x1
			dy := y2 - y1
			g := gcd(dx, dy)
			dx /= g
			dy /= g
			key := slopeKey(dx, dy)
			allSlopes[key]++
		}
	}

	var totalPairs int64
	for _, cnt := range allSlopes {
		if cnt >= 2 {
			totalPairs += cnt * (cnt - 1) / 2
		}
	}

	// Count parallelograms (lines with same slope and same length)
	parallelogramSlopes := make(map[string]int64)
	for i := int64(0); i < n; i++ {
		x1, y1 := points[i][0], points[i][1]
		for j := i + 1; j < n; j++ {
			x2, y2 := points[j][0], points[j][1]
			dx := x2 - x1
			dy := y2 - y1
			g := gcd(dx, dy)
			dx /= g
			dy /= g
			length := dx*dx + dy*dy
			key := slopeKeyWithLength(dx, dy, length)
			parallelogramSlopes[key]++
		}
	}

	var parallelogramPairs int64
	for _, cnt := range parallelogramSlopes {
		if cnt >= 2 {
			parallelogramPairs += cnt * (cnt - 1) / 2
		}
	}

	return totalPairs - parallelogramPairs
}

func gcd(a, b int64) int64 {
	if a < 0 {
		a = -a
	}
	if b < 0 {
		b = -b
	}
	for b != 0 {
		a, b = b, a%b
	}
	return a
}

func slopeKey(dx, dy int64) string {
	return strconv.FormatInt(dx, 10) + "," + strconv.FormatInt(dy, 10)
}

func slopeKeyWithLength(dx, dy, length int64) string {
	var sb strings.Builder
	sb.WriteString(strconv.FormatInt(dx, 10))
	sb.WriteString(",")
	sb.WriteString(strconv.FormatInt(dy, 10))
	sb.WriteString(",")
	sb.WriteString(strconv.FormatInt(length, 10))
	return sb.String()
}
